module RefModule (  
    input [15:0] input_array,  
    input [3:0] target,  
    output reg found  
);  
    integer obf_i;  
    always @(*) begin  
        found = 0;  
        for (obf_i = 0; obf_i < 4; obf_i = obf_i + 1) begin  
            if (input_array[4*obf_i +: 4] == target) begin  
                found = 1;  
            end  
        end  
    end  
endmodule
